import React from "react";
import { useQuery } from "@tanstack/react-query";
import { Link, useSearchParams } from "react-router-dom";
import { 
  projectName, 
  shortModel, 
  formatDate, 
  acceptanceRate, 
  firstUserMessage 
} from "../utils.ts";

const Sessions: React.FC = () => {
