export function esc(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

export function projectName(workdir: string | null): string {
  if (!workdir) return "unknown";
  return workdir.split("/").pop() || workdir;
}

export function shortModel(model: string): string {
  return model.replace("claude-", "").replace(/-\d{8}$/, "");
}

export function formatDate(ts: number): string {
  return new Date(ts * 1000).toLocaleString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

export function acceptanceRate(accepted: number, added: number): string {
  if (!added) return "—";
  return `${Math.round((accepted / added) * 100)}%`;
}

export function firstUserMessage(messagesJson: string): string {
  try {
    const parsed = JSON.parse(messagesJson);
    const msgs = Array.isArray(parsed) ? parsed : parsed.messages ?? [];
    const first = msgs.find((m: { type: string }) => m.type === "user");
    const text: string = first?.text ?? "";
    return text.slice(0, 120) + (text.length > 120 ? "…" : "");
  } catch {
    return "";
  }
}
import type { ServerWebSocket } from "bun";
import { getSessionsAfter, type Session } from "./db.ts";

export interface WebSocketData {
  createdAt: number;
}

const clients = new Set<ServerWebSocket<WebSocketData>>();
let lastCheckTime = Math.floor(Date.now() / 1000);

export const wsHandlers = {
  open(ws: ServerWebSocket<WebSocketData>) {
    clients.add(ws);
    console.log(`[WS] Client connected. Total: ${clients.size}`);
  },
  message(ws: ServerWebSocket<WebSocketData>, message: string | Buffer) {
    // We don't expect messages from client, but log for debug
    console.log(`[WS] Received message: ${message}`);
  },
  close(ws: ServerWebSocket<WebSocketData>) {
    clients.delete(ws);
    console.log(`[WS] Client disconnected. Total: ${clients.size}`);
  },
};

// Start the polling loop
setInterval(() => {
  if (clients.size === 0) {
    lastCheckTime = Math.floor(Date.now() / 1000);
    return;
  }

  const newSessions = getSessionsAfter(lastCheckTime);
  if (newSessions.length > 0) {
    console.log(`[WS] Found ${newSessions.length} new sessions. Broadcasting...`);

    for (const session of newSessions) {
      const message = JSON.stringify({
        type: "session.new",
        payload: session,
      });

      for (const client of clients) {
        client.send(message);
      }

      if (session.created_at > lastCheckTime) {
        lastCheckTime = session.created_at;
      }
    }
  } else {
    lastCheckTime = Math.floor(Date.now() / 1000);
  }
}, 30000);

console.log("[WS] Polling loop started (30s interval)");
import api from "./api.ts";
import { wsHandlers, type WebSocketData } from "./ws.ts";

const PORT = parseInt(process.env.PORT ?? "3333", 10);

const server = Bun.serve<WebSocketData>({
  port: PORT,
  fetch(req, server) {
    const url = new URL(req.url);

    // 1. WebSocket upgrade
    if (url.pathname === "/ws") {
      const success = server.upgrade(req, {
        data: { createdAt: Date.now() },
      });
      return success ? undefined : new Response("Upgrade failed", { status: 400 });
    }

    // 2. API routes
    if (url.pathname.startsWith("/api")) {
      return api.fetch(req);
    }

    // 3. Static files & SPA fallback
    // In a real app we'd bundle this, but for this task we'll serve from src/client
    // and assume the dev server/bundler handles the rest or we serve them as is
    // for Bun's own transpile-on-the-fly (if configured) or just serve index.html

    const filePath = url.pathname === "/" ? "/index.html" : url.pathname;
    const file = Bun.file(`./dist/client${filePath}`);

    return file.exists().then((exists) => {
      if (exists) {
        return new Response(file);
      }
      // SPA Fallback: serve index.html for all other routes
      return new Response(Bun.file("./dist/client/index.html"));
    });
  },
  websocket: wsHandlers,
});

console.log(`Git AI Dashboard → http://localhost:${server.port}`);

